+const PLANNING_ONLY_COMPLETION_RE =
+  /\b(?:done|finished|implemented|updated|fixed|changed|ran|verified|found|here(?:'s| is) what|blocked by|the blocker is)\b/i;
+
+export const PLANNING_ONLY_RETRY_INSTRUCTION =
